from __future__ import annotations

INDEX_HTML = '<!doctype html>\n<html lang="zh-CN">\n<head>\n  <meta charset="utf-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1" />\n  <title>全球上市公司文件下载工具 · Vercel 轻量版</title>\n  <style>\n    :root { color-scheme: light; --bg:#f6f8fb; --card:#fff; --text:#172033; --muted:#62708a; --blue:#2563eb; --line:#dbe3ef; }\n    * { box-sizing: border-box; }\n    body { margin: 0; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Microsoft YaHei", sans-serif; background: var(--bg); color: var(--text); }\n    header { padding: 32px 20px 16px; max-width: 1180px; margin: auto; }\n    h1 { margin: 0 0 8px; font-size: 30px; }\n    p { color: var(--muted); line-height: 1.6; }\n    main { max-width: 1180px; margin: auto; padding: 0 20px 40px; display: grid; gap: 16px; }\n    .card { background: var(--card); border: 1px solid var(--line); border-radius: 16px; padding: 18px; box-shadow: 0 10px 30px rgba(15, 23, 42, .04); }\n    .row { display: flex; gap: 10px; flex-wrap: wrap; align-items: center; }\n    input[type="text"] { flex: 1; min-width: 240px; padding: 12px 14px; border: 1px solid var(--line); border-radius: 12px; font-size: 16px; }\n    button { border: 0; background: var(--blue); color: white; padding: 11px 16px; border-radius: 12px; cursor: pointer; font-weight: 650; }\n    button.secondary { background: #eef2ff; color: #1e40af; }\n    button:disabled { opacity: .55; cursor: not-allowed; }\n    label { display: inline-flex; gap: 6px; align-items: center; margin: 4px 12px 4px 0; color: #263248; }\n    .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(230px, 1fr)); gap: 10px; }\n    .company, .item { border: 1px solid var(--line); border-radius: 12px; padding: 12px; background: #fbfdff; }\n    .company strong, .item strong { display:block; margin-bottom:4px; }\n    .muted { color: var(--muted); font-size: 13px; }\n    .pill { display:inline-block; padding:2px 8px; border-radius:999px; background:#eef2ff; color:#1e40af; font-size:12px; margin:2px 4px 2px 0; }\n    .hidden { display: none; }\n    .status { white-space: pre-wrap; color: #334155; }\n    a { color: var(--blue); }\n    .warn { background:#fff7ed; border-color:#fed7aa; }\n  </style>\n</head>\n<body>\n  <header>\n    <h1>📊 全球上市公司文件下载工具 · Vercel 轻量版</h1>\n    <p>支持公司搜索、文件链接发现、小体积 ZIP 打包与网页转 PDF。完整 Streamlit 版更适合长耗时和大文件下载。</p>\n  </header>\n  <main>\n    <section class="card warn">\n      <strong>部署说明</strong>\n      <p>Vercel Serverless 不适合直接运行 Streamlit 长连接服务；此页面是为 Vercel 单独适配的轻量版。若 ZIP 过大或检索耗时过长，请使用 Streamlit Cloud 正式版。</p>\n    </section>\n\n    <section class="card">\n      <h2>1. 公司搜索</h2>\n      <div class="row">\n        <input id="query" type="text" placeholder="Intel、INTC、Siltronic、SUMCO、TSMC、Infineon、中芯国际…" />\n        <button id="searchBtn">搜索</button>\n      </div>\n      <p id="searchStatus" class="status"></p>\n      <div id="companies" class="grid"></div>\n    </section>\n\n    <section id="optionsCard" class="card hidden">\n      <h2>2. 选择文件范围</h2>\n      <p id="selectedCompany"></p>\n      <h3>文件类型</h3>\n      <div id="kindBox"></div>\n      <h3>年份</h3>\n      <div><label><input type="checkbox" id="allYears"> 全选年份</label></div>\n      <div id="yearBox"></div>\n      <h3>季度</h3>\n      <div><label><input type="checkbox" id="allQuarters" checked> 全选季度</label></div>\n      <div id="quarterBox"></div>\n      <button id="filingsBtn">获取文件列表</button>\n      <p id="filingsStatus" class="status"></p>\n    </section>\n\n    <section id="resultsCard" class="card hidden">\n      <h2>3. 文件清单与打包</h2>\n      <p class="muted">默认勾选前 8 条可下载/网页链接；Vercel 轻量版建议每次打包不超过 12 条。</p>\n      <div class="row">\n        <button id="selectFirstBtn" class="secondary">勾选前 8 条</button>\n        <button id="packageBtn">打包所选链接</button>\n      </div>\n      <p id="packageStatus" class="status"></p>\n      <div id="items"></div>\n    </section>\n  </main>\n\n  <script>\n    const kindLabels = {\n      annual: "年度报告",\n      quarterly: "季度 / 中期报告",\n      prospectus: "招股说明书",\n      transcript: "Earnings Call Transcript",\n      presentation: "Earnings Presentation / IR Deck",\n      proxy: "Proxy 代理声明",\n    };\n    let selectedCompany = null;\n    let filingItems = [];\n\n    const $ = (id) => document.getElementById(id);\n    const currentYear = new Date().getFullYear();\n\n    function initOptions() {\n      $("kindBox").innerHTML = Object.entries(kindLabels).map(([key, label]) =>\n        `<label><input type="checkbox" name="kind" value="${key}" ${key === "annual" ? "checked" : ""}> ${label}</label>`\n      ).join("");\n      $("yearBox").innerHTML = Array.from({length: 20}, (_, i) => currentYear - i).map((year, i) =>\n        `<label><input type="checkbox" name="year" value="${year}" ${i < 3 ? "checked" : ""}> ${year}</label>`\n      ).join("");\n      $("quarterBox").innerHTML = ["全年", "Q1", "Q2", "Q3", "Q4"].map(q =>\n        `<label><input type="checkbox" name="quarter" value="${q}" checked> ${q}</label>`\n      ).join("");\n    }\n\n    function checkedValues(name) {\n      return Array.from(document.querySelectorAll(`input[name="${name}"]:checked`)).map(el => el.value);\n    }\n\n    async function api(path, options = {}) {\n      const res = await fetch(path, options);\n      const data = await res.json();\n      if (!res.ok || data.error) throw new Error(data.error || `HTTP ${res.status}`);\n      return data;\n    }\n\n    function renderCompanies(results) {\n      $("companies").innerHTML = results.map((company, index) => `\n        <div class="company">\n          <strong>${company.flag || "🌐"} ${company.name || company.name_en || "-"}</strong>\n          <div class="muted">${company.name_en || ""}</div>\n          <span class="pill">${company.ticker || company.local_code || "-"}</span>\n          <span class="pill">${company.exchange || company.market || "-"}</span>\n          <span class="pill">${company.source || ""}</span>\n          <div style="margin-top:10px"><button onclick="selectCompany(${index})">选择</button></div>\n        </div>\n      `).join("");\n      window.companyResults = results;\n    }\n\n    window.selectCompany = (index) => {\n      selectedCompany = window.companyResults[index];\n      $("optionsCard").classList.remove("hidden");\n      $("resultsCard").classList.add("hidden");\n      $("selectedCompany").innerHTML = `<strong>${selectedCompany.name || selectedCompany.name_en}</strong> · ${selectedCompany.ticker || selectedCompany.local_code || ""} · ${selectedCompany.exchange || ""}`;\n    };\n\n    async function search() {\n      const query = $("query").value.trim();\n      if (!query) return;\n      $("searchStatus").textContent = "正在搜索…";\n      $("companies").innerHTML = "";\n      try {\n        const data = await api(`/api/search?q=${encodeURIComponent(query)}`);\n        $("searchStatus").textContent = data.results.length ? `找到 ${data.results.length} 个结果。` : "未找到结果。";\n        renderCompanies(data.results);\n      } catch (err) {\n        $("searchStatus").textContent = `搜索失败：${err.message}`;\n      }\n    }\n\n    async function fetchFilings() {\n      if (!selectedCompany) return;\n      $("filingsStatus").textContent = "正在获取文件列表…";\n      $("items").innerHTML = "";\n      try {\n        const data = await api("/api/filings", {\n          method: "POST",\n          headers: {"Content-Type": "application/json"},\n          body: JSON.stringify({company: selectedCompany, kinds: checkedValues("kind"), years: checkedValues("year"), quarters: checkedValues("quarter")}),\n        });\n        filingItems = data.results || [];\n        $("filingsStatus").textContent = `找到 ${filingItems.length} 条。`;\n        renderItems();\n        $("resultsCard").classList.remove("hidden");\n      } catch (err) {\n        $("filingsStatus").textContent = `获取失败：${err.message}`;\n      }\n    }\n\n    function renderItems() {\n      $("items").innerHTML = filingItems.map((item, index) => `\n        <div class="item">\n          <label><input type="checkbox" name="item" value="${index}" ${index < 8 ? "checked" : ""}></label>\n          <strong><a href="${item.url}" target="_blank" rel="noopener">${item.title || item.url}</a></strong>\n          <span class="pill">${item.source || "-"}</span>\n          <span class="pill">${item.kind || item.form || "-"}</span>\n          <span class="pill">${item.date || ""}</span>\n          <div class="muted">${item.note || ""}</div>\n        </div>\n      `).join("");\n    }\n\n    async function packageSelected() {\n      const selected = checkedValues("item").map(i => filingItems[Number(i)]).filter(Boolean).slice(0, 12);\n      if (!selected.length) return;\n      $("packageStatus").textContent = "正在下载、网页转 PDF、打包 ZIP…";\n      try {\n        const data = await api("/api/package", {\n          method: "POST",\n          headers: {"Content-Type": "application/json"},\n          body: JSON.stringify({company: selectedCompany, items: selected}),\n        });\n        const bytes = Uint8Array.from(atob(data.content_base64), c => c.charCodeAt(0));\n        const blob = new Blob([bytes], {type: "application/zip"});\n        const url = URL.createObjectURL(blob);\n        const a = document.createElement("a");\n        a.href = url;\n        a.download = data.filename || "documents.zip";\n        a.click();\n        URL.revokeObjectURL(url);\n        $("packageStatus").textContent = `已生成 ${data.filename}，下载文件 ${data.downloaded || 0} 个。`;\n      } catch (err) {\n        $("packageStatus").textContent = `打包失败：${err.message}`;\n      }\n    }\n\n    $("searchBtn").addEventListener("click", search);\n    $("query").addEventListener("keydown", e => { if (e.key === "Enter") search(); });\n    $("filingsBtn").addEventListener("click", fetchFilings);\n    $("packageBtn").addEventListener("click", packageSelected);\n    $("selectFirstBtn").addEventListener("click", () => {\n      document.querySelectorAll(\'input[name="item"]\').forEach((el, i) => { el.checked = i < 8; });\n    });\n    $("allYears").addEventListener("change", e => {\n      document.querySelectorAll(\'input[name="year"]\').forEach(el => { el.checked = e.target.checked; });\n    });\n    $("allQuarters").addEventListener("change", e => {\n      document.querySelectorAll(\'input[name="quarter"]\').forEach(el => { el.checked = e.target.checked; });\n    });\n    initOptions();\n  </script>\n</body>\n</html>\n'
